#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct UserData {
    uint32_t user_id;
    std::string name;

    void serialise(auto& stream) {
        stream << user_id << name;
    }
};

void serialize_object(hexi::pmc::binary_stream_writer& writer, const UserData& data) {
    // Create a stream_write_adaptor and call the object's serialise method
    hexi::pmc::stream_write_adaptor adaptor(writer);
    data.serialise(adaptor);
}

void deserialize_object(hexi::pmc::binary_stream_reader& reader, UserData& data) {
    // Create a stream_read_adaptor and call the object's serialise method
    hexi::pmc::stream_read_adaptor adaptor(reader);
    data.serialise(adaptor);
}
```

**Explanation:**

1. **Serialization (`serialize_object`):**
   - Creates a `stream_write_adaptor` from the `binary_stream_writer`
   - Calls the object's `serialise` method with the adaptor
   - The `UserData::serialise` method uses `stream <<` operators to serialize `user_id` and `name`

2. **Deserialization (`deserialize_object`):**
   - Creates a `stream_read_adaptor` from the `binary_stream_reader`
   - Calls the object's `serialise` method with the adaptor  
   - The `UserData::serialise` method uses `stream <<` operators, but since we're using a read adaptor, this will actually deserialize the data into the object's members

The `UserData::serialise` method is designed to work with both read and write adaptors through the same interface, making the serialization/deserialization process symmetric.

