    // Use template write() method for each field
    adaptor.write(data.id);
    adaptor.write(data.value);
    adaptor.write(data.ratio);

    return buffer;
}

TypedData read_typed_data(const std::vector<uint8_t>& buffer) {
    std::vector<uint8_t> temp_buffer = buffer;
    hexi::pmc::buffer_read_adaptor read_adaptor(temp_buffer);

    TypedData data;

    // Use template read() method for each field
    read_adaptor.read(&data.id);
    read_adaptor.read(&data.value);
    read_adaptor.read(&data.ratio);

    return data;
}

